# Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
sub solve {
  my ($rut) = @_;
  $rut = "" unless defined $rut;
  my $clean = uc($rut);
  $clean =~ s/[\.\-\s]//g;
  return 0 if length($clean) < 2;

  my $body = substr($clean, 0, length($clean)-1);
  my $dv   = substr($clean, -1);

  return 0 unless $body =~ /^\d+$/;

  my $sum = 0;
  my $mul = 2;
  for my $ch (reverse split //, $body) {
    $sum += (ord($ch) - ord('0')) * $mul;
    $mul = ($mul == 7) ? 2 : ($mul + 1);
  }

  my $mod = 11 - ($sum % 11);
  my $dvCalc = ($mod == 11) ? '0' : ($mod == 10) ? 'K' : $mod;
  return $dv eq $dvCalc ? 1 : 0;
}

snippets.C0650:
# C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
# Perl · Text::CSV
# cpan Text::CSV
use Text::CSV;

sub solve {
  my ($in, $out) = ("input.csv","output.csv");
  my $csv = Text::CSV->new({ binary => 1, auto_diag => 1 });
  open my $fh, "<:encoding(UTF-8)", $in or die $!;
  open my $oh, ">:encoding(UTF-8)", $out or die $!;

  my $header = $csv->getline($fh);
  $csv->say($oh, $header);

  my %idx; for my $i (0..$#$header){ $idx{lc $header->[$i]} = $i }
  my $email_i = $idx{"email"};

  while (my $row = $csv->getline($fh)) {
    if (defined $email_i) { $row->[$email_i] = lc($row->[$email_i] // "") }
    $csv->say($oh, $row);
  }
  close $fh; close $oh;
}

