# C0651 · Consumir API HTTP (GET y POST JSON) (Intermedio, HTTP)
# Perl · LWP::UserAgent
use LWP::UserAgent;
use JSON qw(decode_json encode_json);

sub solve {
  my $base = "http://localhost:3000";
  my $ua = LWP::UserAgent->new(timeout => 5);

  my $items = decode_json($ua->get("$base/api/items")->decoded_content);
  my $res = $ua->post("$base/api/items",
    "Content-Type" => "application/json",
    Content => encode_json({ name=>"Item", qty=>1 })
  );
  my $created = decode_json($res->decoded_content);
  return { items => $items, created => $created };
}

