# C0656 · Regex: extraer emails (Básico, Texto)
sub solve {
  my ($text) = @_;
  my %seen;
  my @out;
  while ($text =~ /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig) {
    my $m = $&;
    next if $seen{$m}++;
    push @out, $m;
  }
  return \@out;
}

