# C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
# Perl: stdin (Enter)
sub solve {
  print "Escribe una tecla y Enter (w/a/s/d, q):\n";
  while (my $line = <STDIN>) {
    chomp $line;
    next if $line eq "";
    my $k = lc substr($line,0,1);
    last if $k eq "q";
    print "Mover: arriba\n" if $k eq "w";
    print "Mover: abajo\n" if $k eq "s";
    print "Mover: izquierda\n" if $k eq "a";
    print "Mover: derecha\n" if $k eq "d";
  }
}
